static int __init tk_aux_sysfs_init(void)
{
	struct kobject *auxo, *tko = kobject_create_and_add("time", kernel_kobj);
	int ret = -ENOMEM;

	if (!tko)
		return ret;

	auxo = kobject_create_and_add("aux_clocks", tko);
	if (!auxo)
		goto err_clean;

	for (int i = 0; i < nr_aux_clocks; i++) {
		char id[3] = { [0] = '0' + i / 10, [1] = '0' + i % 10, };
		struct kobject *clk;

		/* Skip leading zero for single-digit IDs */
		if (i < 10)
			id[1] = '\0';

		clk = kobject_create_and_add(id, auxo);
		if (!clk) {
			ret = -ENOMEM;
			goto err_clean;
		}

		ret = sysfs_create_group(clk, &aux_clock_enable_attr_group);
		if (ret)
			goto err_clean;
	}
	return 0;

err_clean:
	kobject_put(auxo);
	kobject_put(tko);
	return ret;
}

