input.newString:
// SPDX-License-Identifier: GPL-2.0-only

#include <linux/linkage.h>
#include <linux/mmap_lock.h>
#include <linux/mm.h>
#include <linux/slab.h>
#include <linux/time_namespace.h>
#include <linux/types.h>
#include <linux/vdso_datastore.h>
#include <vdso/datapage.h>

/*
 * The vDSO data page - dynamically allocated to accommodate variable clock
 * counts. The layout is:
 *
 *   struct vdso_time_data (header with offsets)
 *   struct vdso_clock clock_data[CS_BASES] (2 entries)
 *     For each: struct vdso_timestamp basetime[nr_clock_ids]
 *   struct vdso_clock aux_clock_data[nr_aux_clocks]
 *     For each: struct vdso_timestamp basetime[nr_clock_ids]
 */
#ifdef CONFIG_GENERIC_GETTIMEOFDAY
static struct vdso_time_data *vdso_time_data_store;
struct vdso_time_data *vdso_k_time_data;

/*
 * vdso_time_data_init - Allocate and initialize the VDSO time data page
 * @nr_clock_ids:	Number of clock IDs per clock
 * @nr_aux:		Number of auxiliary clocks
 *
 * Must be called once during boot (from timekeeping_init()) before any VDSO
 * lookups occur.
 */
int __init vdso_time_data_init(unsigned int nr_clock_ids, unsigned int nr_aux)
{
	struct vdso_time_data *vd;
	size_t total;
	unsigned int i;
	struct vdso_clock *vc;
	u32 clock_off, aux_off;

	total = vdso_time_data_total_size(nr_clock_ids, nr_aux);
	/* Round up to page size for mmap compatibility */
	total = PAGE_ALIGN(total);

	vd = __vmalloc(total, GFP_KERNEL_ACCOUNT | __GFP_ZERO);
	if (!vd)
		return -ENOMEM;

	vd->nr_clock_ids = nr_clock_ids;
	vd->nr_aux_clocks = nr_aux;

	/* clock_data starts immediately after the vdso_time_data header */
	clock_off = sizeof(struct vdso_time_data);
	vd->clock_data_off = clock_off;

	/* aux_clock_data starts after clock_data array */
	aux_off = clock_off + vdso_clock_data_size(CS_BASES, nr_clock_ids);
	vd->aux_clock_data_off = aux_off;

	vdso_k_time_data = vd;

	pr_debug("VDSO time data: %zu bytes, %u clock IDs, %u aux clocks\n",
		 total, nr_clock_ids, nr_aux);
	return 0;
}
#else
struct vdso_time_data *vdso_k_time_data;
#endif /* CONFIG_GENERIC_GETTIMEOFDAY */

